mapper.select:
SELECT EXISTS (
    SELECT 1
    FROM tb_inspection_template
    WHERE company_id = #{companyId}
      AND category_id = #{categoryId}
      AND template_name = #{templateName}
      AND version = #{version}

        AND template_id <> #{excludeTemplateId}

)

SELECT EXISTS (
    SELECT 1
    FROM tb_inspection_template_item i
    INNER JOIN tb_inspection_template t
        ON t.template_id = i.template_id
    WHERE t.company_id = #{companyId}
      AND i.template_id = #{templateId}
      AND i.item_name = #{itemName}

        AND i.item_id <> #{excludeItemId}

)

SELECT EXISTS (
    SELECT 1
    FROM tb_inspection_template_item_option o
    INNER JOIN tb_inspection_template_item i
        ON i.item_id = o.item_id
    INNER JOIN tb_inspection_template t
        ON t.template_id = i.template_id
    WHERE t.company_id = #{companyId}
      AND i.template_id = #{templateId}
      AND o.item_id = #{itemId}
      AND (o.option_label = #{optionLabel} OR o.option_value = #{optionValue})

        AND o.option_id <> #{excludeOptionId}

)

SELECT COALESCE(MAX(i.sort_order), -10) + 10
FROM tb_inspection_template_item i
INNER JOIN tb_inspection_template t
    ON t.template_id = i.template_id
WHERE t.company_id = #{companyId}
  AND i.template_id = #{templateId}

SELECT COALESCE(MAX(o.sort_order), -10) + 10
FROM tb_inspection_template_item_option o
INNER JOIN tb_inspection_template_item i
    ON i.item_id = o.item_id
INNER JOIN tb_inspection_template t
    ON t.template_id = i.template_id
WHERE t.company_id = #{companyId}
  AND i.template_id = #{templateId}
  AND o.item_id = #{itemId}

SELECT
    COUNT(*) AS total_count,
    COALESCE(SUM(CASE WHEN i.item_id IN

            #{itemId}

        THEN 1 ELSE 0 END), 0) AS matched_count
FROM tb_inspection_template_item i
INNER JOIN tb_inspection_template t
    ON t.template_id = i.template_id
WHERE t.company_id = #{companyId}
  AND i.template_id = #{templateId}
  AND i.item_group = #{itemGroup}

SELECT
    COUNT(*) AS total_count,
    COALESCE(SUM(CASE WHEN o.option_id IN

            #{optionId}

        THEN 1 ELSE 0 END), 0) AS matched_count
FROM tb_inspection_template_item_option o
INNER JOIN tb_inspection_template_item i
    ON i.item_id = o.item_id
INNER JOIN tb_inspection_template t
    ON t.template_id = i.template_id
WHERE t.company_id = #{companyId}
  AND i.template_id = #{templateId}
  AND o.item_id = #{itemId}

mapper.update:
UPDATE tb_inspection_template
SET
    active = #{active},
    updated_at = NOW(6)
WHERE company_id = #{companyId}
  AND template_id = #{templateId}

UPDATE tb_inspection_template
SET updated_at = NOW(6)
WHERE company_id = #{companyId}
  AND template_id = #{templateId}

UPDATE tb_inspection_template_item i
INNER JOIN tb_inspection_template t
    ON t.template_id = i.template_id
SET i.active = #{active}
WHERE t.company_id = #{companyId}
  AND i.template_id = #{templateId}
  AND i.item_id = #{itemId}

UPDATE tb_inspection_template_item i
INNER JOIN tb_inspection_template t
    ON t.template_id = i.template_id
SET i.sort_order = CASE i.item_id

    WHEN #{sortOrder.id} THEN #{sortOrder.sortOrder}

END
WHERE t.company_id = #{companyId}
  AND i.template_id = #{templateId}
  AND i.item_group = #{itemGroup}
  AND i.item_id IN

    #{sortOrder.id}

UPDATE tb_inspection_template_item_option o
INNER JOIN tb_inspection_template_item i
    ON i.item_id = o.item_id
INNER JOIN tb_inspection_template t
    ON t.template_id = i.template_id
SET o.active = FALSE
WHERE t.company_id = #{companyId}
  AND i.template_id = #{templateId}
  AND o.item_id = #{itemId}

UPDATE tb_inspection_template_item_option o
INNER JOIN tb_inspection_template_item i
    ON i.item_id = o.item_id
INNER JOIN tb_inspection_template t
    ON t.template_id = i.template_id
SET
    o.option_label = #{option.optionLabel},
    o.option_value = #{option.optionValue},
    o.sort_order = #{option.sortOrder},
    o.active = #{option.active}
WHERE t.company_id = #{companyId}
  AND i.template_id = #{templateId}
  AND o.item_id = #{option.itemId}
  AND o.option_id = #{option.optionId}

UPDATE tb_inspection_template_item_option o
INNER JOIN tb_inspection_template_item i
    ON i.item_id = o.item_id
INNER JOIN tb_inspection_template t
    ON t.template_id = i.template_id
SET o.active = #{active}
WHERE t.company_id = #{companyId}
  AND i.template_id = #{templateId}
  AND o.item_id = #{itemId}
  AND o.option_id = #{optionId}

UPDATE tb_inspection_template_item_option o
INNER JOIN tb_inspection_template_item i
    ON i.item_id = o.item_id
INNER JOIN tb_inspection_template t
    ON t.template_id = i.template_id
SET o.sort_order = CASE o.option_id

    WHEN #{sortOrder.id} THEN #{sortOrder.sortOrder}

END
WHERE t.company_id = #{companyId}
  AND i.template_id = #{templateId}
  AND o.item_id = #{itemId}
  AND o.option_id IN

    #{sortOrder.id}
